sql:
SELECT season_id, home_wins
FROM team_seasons
ORDER BY season_id;

SELECT MAX(pts) AS max_points
FROM team_seasons
WHERE season_id = (
    SELECT MAX(season_id)
    FROM seasons
);

SELECT COUNT(DISTINCT player_id) as total_players
FROM team_rosters
WHERE season_id = 0;

SELECT AVG(salary) AS average_salary
FROM players
WHERE position = 'defense';

SELECT SUM(gf) AS total_goals_scored
FROM team_seasons
WHERE team_id = (SELECT team_id FROM teams WHERE team_name = 'Team A');
